head.b:skin:
/*
 * CORE PREMIUM FRAMEWORK STYLES
 * Designed specifically for AdSense high-conversion rates.
 */
:root {
    --primary: #1a73e8;
    --primary-dark: #1557b0;
    --primary-light: #e8f0fe;
    --accent: #d93025;
    --secondary: #202124;
    --text-main: #3c4043;
    --text-muted: #5f6368;
    --bg: #f8f9fa;
    --surface: #ffffff;
    --border: #dadce0;
    --shadow: 0 1px 3px rgba(60,64,67,0.3), 0 4px 8px 3px rgba(60,64,67,0.15);
    --transition: all 0.25s cubic-bezier(0.4, 0, 0.2, 1);
    --radius: 8px;
}

body.dark-mode {
    --bg: #0f172a;
    --surface: #1e293b;
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
    --border: #334155;
    --secondary: #f8fafc;
}

* { margin: 0; padding: 0; box-sizing: border-box; }
body { background: var(--bg); font-family: 'Inter', 'Hind Siliguri', sans-serif; color: var(--text-main); line-height: 1.6; padding-top: 160px; transition: var(--transition); }
.container { max-width: 1280px; margin: 0 auto; padding: 0 20px; }

/* HEADER & NAVIGATION */
header { background: var(--surface); position: fixed; top: 0; left: 0; width: 100%; z-index: 1000; box-shadow: 0 1px 2px rgba(60,64,67,0.3); border-bottom: 1px solid var(--border); }
.top-bar { background: var(--secondary); color: var(--surface); padding: 8px 0; font-size: 13px; }
.top-flex { display: flex; justify-content: space-between; align-items: center; }
.top-links a { color: #bdc1c6; text-decoration: none; margin-left: 15px; }
.top-links a:hover { color: #fff; }

.main-header { padding: 15px 0; display: flex; justify-content: space-between; align-items: center; }
.logo { font-size: 28px; font-weight: 900; color: var(--primary); text-decoration: none; display: flex; align-items: center; gap: 10px; }
.logo span { color: var(--secondary); }

.header-ad { width: 728px; height: 90px; background: rgba(0,0,0,0.02); border: 1px dashed var(--border); display: flex; align-items: center; justify-content: center; font-size: 11px; color: var(--text-muted); }

nav { background: var(--surface); border-bottom: 1px solid var(--border); }
.nav-list { display: flex; list-style: none; overflow-x: auto; white-space: nowrap; }
.nav-list li a { display: block; padding: 16px 20px; text-decoration: none; color: var(--text-main); font-weight: 700; font-size: 14px; transition: var(--transition); }
.nav-list li a:hover, .nav-list li.active a { color: var(--primary); background: var(--primary-light); }

/* ADVANCED SUB-NAVIGATION & SEARCH */
.sub-nav { background: #fff; border-bottom: 1px solid var(--border); padding: 10px 0; }
body.dark-mode .sub-nav { background: #1e293b; }
.sub-flex { display: flex; justify-content: space-between; align-items: center; gap: 20px; }

.search-wrapper { position: relative; flex: 1; max-width: 600px; display: flex; background: var(--bg); border: 1px solid var(--border); border-radius: 30px; padding: 4px 15px; align-items: center; }
.search-wrapper input { border: none; background: transparent; padding: 8px 10px; width: 100%; outline: none; font-size: 15px; color: var(--text-main); font-family: inherit; }
.search-wrapper i { color: var(--text-muted); }

.ticker { flex: 1; overflow: hidden; display: flex; align-items: center; background: var(--primary-light); border-radius: 30px; padding: 8px 15px; max-width: 400px; font-size: 13px; font-weight: 600; color: var(--primary); }

/* AD SPOTS */
.ad-container { margin: 25px auto; text-align: center; overflow: hidden; display: flex; flex-direction: column; align-items: center; }
.ad-label { font-size: 10px; color: var(--text-muted); text-transform: uppercase; margin-bottom: 6px; letter-spacing: 1px; }
.ad-box { background: rgba(0,0,0,0.02); border: 1px dashed var(--border); width: 100%; min-height: 90px; display: flex; align-items: center; justify-content: center; font-size: 12px; color: var(--text-muted); }

/* MAIN CONTENT GRID */
.main-wrapper { display: grid; grid-template-columns: 1fr 320px; gap: 30px; margin-top: 30px; }

/* CATEGORY DIRECTORY CARDS (THE HEART OF THE HUB) */
.cat-box { background: var(--surface); border: 1px solid var(--border); border-radius: var(--radius); padding: 30px; margin-bottom: 35px; box-shadow: 0 1px 2px rgba(60,64,67,0.1); }
.cat-header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 25px; border-bottom: 2px solid var(--bg); padding-bottom: 15px; }
.cat-header h2 { font-size: 22px; font-weight: 800; display: flex; align-items: center; gap: 10px; color: var(--secondary); }
.cat-header h2 i { color: var(--primary); font-size: 24px; }
.badge { background: var(--primary-light); color: var(--primary); font-size: 12px; font-weight: 700; padding: 4px 10px; border-radius: 20px; }

.news-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(115px, 1fr)); gap: 15px; }
.news-card { background: var(--surface); border: 1px solid var(--border); border-radius: 8px; padding: 15px 5px; text-align: center; transition: var(--transition); cursor: pointer; text-decoration: none; position: relative; }
.news-card:hover { transform: translateY(-5px); box-shadow: var(--shadow); border-color: var(--primary); }
.news-card img { width: 42px; height: 42px; object-fit: contain; margin-bottom: 10px; background: #fff; padding: 4px; border-radius: 4px; border: 1px solid #eee; }
.news-card span { display: block; font-weight: 700; font-size: 13px; color: var(--text-main); white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

/* SIDEBAR COMPONENTS */
.sidebar-widget { background: var(--surface); padding: 20px; border-radius: var(--radius); border: 1px solid var(--border); margin-bottom: 30px; box-shadow: 0 1px 2px rgba(60,64,67,0.1); }
.widget-title { font-size: 16px; font-weight: 800; border-left: 4px solid var(--primary); padding-left: 10px; margin-bottom: 20px; color: var(--secondary); }

/* FOOTER */
footer { background: var(--secondary); color: #fff; padding: 80px 0 30px; margin-top: 60px; }
.footer-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 40px; }
.footer-logo { font-size: 24px; font-weight: 900; color: #fff; margin-bottom: 20px; display: block; }
.footer-logo span { color: var(--primary); }
.footer-title { font-size: 16px; font-weight: 700; color: var(--primary-light); margin-bottom: 25px; display: block; }
.footer-links { list-style: none; }
.footer-links li { margin-bottom: 12px; }
.footer-links a { color: #bdc1c6; text-decoration: none; font-size: 14px; transition: var(--transition); }
.footer-links a:hover { color: #fff; padding-left: 5px; }

/* MODAL READER */
.reader-modal { position: fixed; top: 0; left: 0; width: 100%; height: 100%; background: #fff; z-index: 9999; display: none; flex-direction: column; }
body.dark-mode .reader-modal { background: #0f172a; }
.reader-header { background: var(--secondary); color: #fff; padding: 12px 25px; display: flex; justify-content: space-between; align-items: center; }
.reader-btn { background: var(--primary); color: #fff; border: none; padding: 8px 20px; border-radius: 4px; cursor: pointer; font-weight: 700; font-size: 13px; text-decoration: none; }
iframe#reader-frame { flex: 1; border: none; width: 100%; }

@media (max-width: 1024px) {
    .header-ad { display: none; }
    body { padding-top: 130px; }
}
@media (max-width: 768px) {
    .main-wrapper { grid-template-columns: 1fr; }
    .ticker { display: none; }
}

body.script:
//
// Date Generation
const options = { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' };
document.getElementById('real-time-date').innerText = new Date().toLocaleDateString('bn-BD', options);

// Dark Mode Function
function toggleTheme() {
    document.body.classList.toggle('dark-mode');
}

// Live Dynamic Search Filter
function filterHub() {
    let input = document.getElementById('live-search').value.toLowerCase();
    let cards = document.querySelectorAll('.news-card');
    cards.forEach(card => {
        let name = card.getAttribute('data-title').toLowerCase();
        if (name.includes(input)) {
            card.style.display = "block";
        } else {
            card.style.display = "none";
        }
    });
}

// Hub Loading System
function openHub(url, name) {
    document.getElementById('active-site-title').innerText = "পড়ছেন: " + name;
    document.getElementById('reader-frame').src = url;
    document.getElementById('ext-tab').href = url;
    document.getElementById('app-reader').style.display = "flex";
    document.body.style.overflow = "hidden";
}

function closeHub() {
    document.getElementById('app-reader').style.display = "none";
    document.getElementById('reader-frame').src = "";
    document.body.style.overflow = "auto";
}
//
